import React, { createContext, useContext, useState, useEffect } from 'react';
import { User } from '../types';

interface AuthContextType {
  user: User | null;
  login: (email: string, password: string) => Promise<boolean>;
  register: (name: string, email: string, password: string) => Promise<boolean>;
  logout: () => void;
  addPoints: (points: number) => void;
  redeemReward: (cost: number) => boolean;
  isLoading: boolean;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const savedUser = localStorage.getItem('eco_user');
    if (savedUser) {
      setUser(JSON.parse(savedUser));
    }
    setIsLoading(false);
  }, []);

  const updatePersistedUser = (updatedUser: User) => {
    setUser(updatedUser);
    localStorage.setItem('eco_user', JSON.stringify(updatedUser));

    // Update in mock DB too
    const db: User[] = JSON.parse(localStorage.getItem('eco_users_db') || '[]');
    const index = db.findIndex(u => u.id === updatedUser.id);
    if (index !== -1) {
      db[index] = { ...db[index], ...updatedUser };
      localStorage.setItem('eco_users_db', JSON.stringify(db));
    }
  };

  const addPoints = (amount: number) => {
    if (!user) return;
    const newPoints = user.points + amount;
    const newLevel = 1 + Math.floor(newPoints / 100);
    updatePersistedUser({ ...user, points: newPoints, level: newLevel });
  };

  const redeemReward = (cost: number): boolean => {
    if (!user || user.points < cost) return false;
    addPoints(-cost);
    return true;
  };

  const login = async (email: string, password: string): Promise<boolean> => {
    await new Promise(r => setTimeout(r, 800));
    const users: User[] = JSON.parse(localStorage.getItem('eco_users_db') || '[]');
    const foundUser = users.find(u => u.email === email && u.password === password);
    if (foundUser) {
      const { password, ...safeUser } = foundUser;
      updatePersistedUser(safeUser as User);
      return true;
    }
    return false;
  };

  const register = async (name: string, email: string, password: string): Promise<boolean> => {
    await new Promise(r => setTimeout(r, 800));
    const users: User[] = JSON.parse(localStorage.getItem('eco_users_db') || '[]');
    if (users.some(u => u.email === email)) return false;

    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      name,
      nativeName: "Student User",
      email,
      password,
      role: 'user',
      avatar: 'https://i.ibb.co/XfXkY0W/user-placeholder.jpg',
      studentId: `SE-${Math.floor(2000 + Math.random() * 500)}`,
      iin: '060912501743',
      birthdate: '12 September 2006',
      financing: 'Грант',
      course: 3,
      status: 'Студент',
      studyingStatus: 'Обучающийся',
      phone: '+77477412440',
      points: 0,
      level: 1
    };

    localStorage.setItem('eco_users_db', JSON.stringify([...users, newUser]));
    const { password: _, ...safeUser } = newUser;
    updatePersistedUser(safeUser as User);
    return true;
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('eco_user');
  };

  return (
    <AuthContext.Provider value={{ user, login, register, logout, addPoints, redeemReward, isLoading }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) throw new Error('useAuth must be used within an AuthProvider');
  return context;
};

import React, { useState, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { Card } from '../components/UI';
import { classifyWaste } from '../services/geminiService';
import { ClassificationResult } from '../types';
import { useAuth } from '../contexts/AuthContext';

const Home: React.FC = () => {
  const [isUploading, setIsUploading] = useState(false);
  const [preview, setPreview] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const navigate = useNavigate();
  const { addPoints } = useAuth();

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setPreview(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleClassify = async () => {
    if (!preview) return;
    setIsUploading(true);
    try {
      const result = await classifyWaste(preview);
      const fullResult = { ...result, imageUrl: preview } as ClassificationResult;

      // Points Logic
      let pointsAwarded = 10;
      if (fullResult.confidence >= 0.9) pointsAwarded += 5; // Precision Bonus
      addPoints(pointsAwarded);

      const history = JSON.parse(localStorage.getItem('waste_history') || '[]');
      localStorage.setItem('waste_history', JSON.stringify([fullResult, ...history]));

      navigate(`/result/${fullResult.id}`, { state: { result: fullResult, pointsAwarded } });
    } catch (err) {
      alert("Classification failed. Please try again.");
    } finally {
      setIsUploading(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto py-12 px-4 sm:px-6">
      <div className="text-center mb-12">
        <h1 className="text-4xl font-extrabold text-gray-900 sm:text-5xl">
          Identify, Sort, <span className="text-blue-600">Sustain.</span>
        </h1>
        <p className="mt-4 text-xl text-gray-600">
          Upload a photo of your waste and let our AI determine how to recycle it correctly.
        </p>
      </div>

      <Card className="p-0 border-none">
        <div 
          className="border-4 border-dashed border-gray-200 rounded-3xl p-12 text-center hover:border-blue-400 transition-colors cursor-pointer bg-white"
          onClick={() => !isUploading && fileInputRef.current?.click()}
        >
          {preview ? (
            <div className="relative inline-block w-full max-w-sm">
              <img src={preview} alt="Preview" className="rounded-xl shadow-lg w-full h-64 object-cover" />
              <button 
                onClick={(e) => { e.stopPropagation(); setPreview(null); }}
                className="absolute -top-3 -right-3 bg-red-500 text-white rounded-full p-1 shadow-md hover:bg-red-600"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                </svg>
              </button>
            </div>
          ) : (
            <div className="space-y-4">
              <div className="mx-auto h-16 w-16 text-blue-500 bg-blue-50 rounded-full flex items-center justify-center">
