const Map: React.FC = () => {
  const mapRef = useRef<any>(null);
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const [filter, setFilter] = useState<string>('All');
  const [selectedContainer, setSelectedContainer] = useState<WasteContainer | null>(null);

  useEffect(() => {
    if (!mapContainerRef.current) return;

    const L = (window as any).L;
    if (!L) return;

    if (!mapRef.current) {
      mapRef.current = L.map(mapContainerRef.current).setView([51.1283, 71.4305], 13);
      L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
        attribution: '&copy; OpenStreetMap contributors'
      }).addTo(mapRef.current);
    }

    // Clear existing markers
    mapRef.current.eachLayer((layer: any) => {
      if (layer instanceof L.Marker) mapRef.current.removeLayer(layer);
    });

    // Add Markers
    SAMPLE_CONTAINERS.filter(c => filter === 'All' || c.type === filter).forEach(container => {
      const marker = L.marker([container.lat, container.lng]).addTo(mapRef.current);
      marker.on('click', () => setSelectedContainer(container));
    });

    return () => {
      // Don't destroy map on every re-render, only on unmount
    };
  }, [filter]);

  const handleNearMe = () => {
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition((pos) => {
        const { latitude, longitude } = pos.coords;
        const L = (window as any).L;
        mapRef.current.setView([latitude, longitude], 15);
        L.marker([latitude, longitude], { 
          icon: L.divIcon({ className: 'bg-blue-600 w-4 h-4 rounded-full border-2 border-white shadow-lg' }) 
        }).addTo(mapRef.current);
      });
    }
  };

  const categories = ['All', ...Object.values(WasteCategory)];

  return (
    <div className="max-w-7xl mx-auto py-8 px-4 sm:px-6 lg:px-8 space-y-6">
      <header className="flex justify-between items-center">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">City Recycling Map</h1>
          <p className="text-gray-500">Find the nearest smart container in Astana.</p>
        </div>
        <button 
          onClick={handleNearMe}
          className="bg-white border border-gray-200 px-4 py-2 rounded-xl text-sm font-bold flex items-center gap-2 hover:bg-gray-50 transition-all shadow-sm"
        >
          📍 Near Me
        </button>
      </header>

      <div className="flex gap-2 overflow-x-auto pb-2">
        {categories.map(cat => (
          <button
            key={cat}
            onClick={() => setFilter(cat)}
            className={`px-4 py-2 rounded-xl text-xs font-bold transition-all whitespace-nowrap ${
              filter === cat ? 'bg-blue-600 text-white shadow-lg shadow-blue-100' : 'bg-white text-gray-500 border border-gray-100 hover:bg-gray-50'
            }`}
          >
            {cat}
          </button>
        ))}
      </div>

      <div className="flex flex-col lg:flex-row gap-6">
        <div className="flex-grow h-[600px] bg-white rounded-3xl shadow-xl overflow-hidden relative">
          <div ref={mapContainerRef} className="w-full h-full"></div>
        </div>

        {selectedContainer && (
          <div className="lg:w-80 animate-fade-in">
            <Card title="Container Info">
              <div className="space-y-4">
                <div>
                  <h4 className="font-bold text-gray-900 text-lg">{selectedContainer.name}</h4>
                  <p className="text-sm text-gray-500">{selectedContainer.address}</p>
                </div>

                <div className="flex justify-between items-center">
                  <Badge category={selectedContainer.type} />
                  <span className={`text-xs font-bold uppercase ${
                    selectedContainer.status === 'available' ? 'text-green-600' : 'text-red-600'
                  }`}>
                    {selectedContainer.status}
                  </span>
                </div>

                <div className="space-y-1.5">
                  <div className="flex justify-between text-xs font-bold text-gray-500">
                    <span>Fill Level</span>
                    <span>{Math.round(selectedContainer.fillLevel * 100)}%</span>
                  </div>
                  <div className="w-full bg-gray-100 h-2 rounded-full overflow-hidden">
                    <div 
                      className={`h-full transition-all duration-1000 ${
                        selectedContainer.fillLevel > 0.8 ? 'bg-red-500' : 'bg-green-500'
                      }`}
                      style={{ width: `${selectedContainer.fillLevel * 100}%` }}
                    />
                  </div>
                </div>

                <button className="w-full py-3 bg-blue-50 text-blue-600 rounded-xl font-bold text-sm hover:bg-blue-100 transition-colors">
                  Get Directions
                </button>
              </div>
            </Card>
          </div>
        )}
      </div>
    </div>
  );
};

export default Map;

